('qb001000-0000-0000-0000-000000000001', '大客户经理面试题库', 'behavioral', 'intermediate', '["大客户","销售","商务"]', '[{"question":"请描述你如何开拓一个新的大客户？","type":"behavioral","difficulty":"medium","reference_answer":"应包含客户调研、接触策略、需求挖掘","tags":["大客户","开拓"]},{"question":"你如何处理大客户的投诉？","type":"situational","difficulty":"medium","reference_answer":"应包含倾听、分析、解决方案、跟进","tags":["客户服务","投诉"]},{"question":"分享一个你成功签下的最大订单经历。","type":"behavioral","difficulty":"hard","reference_answer":"应包含背景、挑战、行动、结果","tags":["销售","案例"]}]', NULL, 'a84bb022-75c1-4f7e-b4d7-3356109b393c', '2026-06-10 10:00:00'),
('qb002000-0000-0000-0000-000000000002', '医疗渠道面试题库', 'technical', 'advanced', '["医疗","渠道","管理"]', '[{"question":"你对医疗行业渠道管理有什么理解？","type":"technical","difficulty":"hard","reference_answer":"应包含行业特点、渠道类型、管理模式","tags":["医疗","渠道"]},{"question":"如何评估一个渠道商的质量？","type":"technical","difficulty":"medium","reference_answer":"应包含资质、业绩、合作意愿","tags":["渠道","评估"]},{"question":"分享你管理过的最大渠道网络。","type":"behavioral","difficulty":"hard","reference_answer":"应包含规模、管理方法、成果","tags":["渠道","管理"]}]', NULL, '100aea8b-936f-42bd-a742-6d923487e23b', '2026-06-11 10:00:00'),
('qb003000-0000-0000-0000-000000000003', '市场BD通用题库', 'behavioral', 'intermediate', '["BD","市场","推广"]', '[{"question":"你如何制定一个区域市场推广计划？","type":"situational","difficulty":"medium","reference_answer":"应包含市场调研、目标设定、策略选择","tags":["市场","推广"]},{"question":"描述一次成功的BD合作经历。","type":"behavioral","difficulty":"medium","reference_answer":"应包含背景、谈判过程、结果","tags":["BD","合作"]},{"question":"你如何衡量BD工作的效果？","type":"technical","difficulty":"easy","reference_answer":"应包含KPI指标、转化率","tags":["BD","指标"]}]', NULL, '5c5133c9-a925-4e61-b034-5212dc52d154', '2026-06-12 10:00:00'),
('qb004000-0000-0000-0000-000000000004', '通用素质面试题库', 'behavioral', 'intermediate', '["通用","素质","软技能"]', '[{"question":"请做一下自我介绍。","type":"behavioral","difficulty":"easy","reference_answer":"应简洁有逻辑","tags":["通用","自我介绍"]},{"question":"你最大的优点和缺点是什么？","type":"behavioral","difficulty":"easy","reference_answer":"应真诚且有改进计划","tags":["通用","自我认知"]},{"question":"你为什么选择我们公司？","type":"behavioral","difficulty":"easy","reference_answer":"应体现对公司了解","tags":["通用","求职动机"]},{"question":"你的职业规划是什么？","type":"behavioral","difficulty":"medium","reference_answer":"应有清晰3-5年规划","tags":["通用","职业规划"]}]', NULL, NULL, '2026-06-13 10:00:00'),
('qb005000-0000-0000-0000-000000000005', '技术岗位面试题库', 'technical', 'advanced', '["技术","编程","算法"]', '[{"question":"请解释什么是RESTful API。","type":"technical","difficulty":"medium","reference_answer":"应包含资源、HTTP方法、状态码","tags":["技术","API"]},{"question":"什么是微服务架构？","type":"technical","difficulty":"hard","reference_answer":"应包含特点、优缺点、适用场景","tags":["技术","架构"]},{"question":"如何优化数据库查询性能？","type":"technical","difficulty":"hard","reference_answer":"应包含索引、缓存、分区","tags":["技术","数据库"]}]', NULL, NULL, '2026-06-14 10:00:00');
